section.programlisting:
#! /usr/scripts/env python3 # -*- coding: UTF-8 -*- ############################################## # Home : http://netkiller.github.io # Author: Neo <netkiller@msn.com> # Data: 2026-02-03 # Description: wav 文件录音 ############################################## import datetime import wave
import pyaudio
FORMAT = pyaudio.paInt16 CHANNELS = 1 RATE = 16000 FRAMES_PER_BUFFER = 2048
if __name__ == '__main__': filename = f"录音：time-{RATE}-" + str(datetime.datetime.now().strftime("%H%M%S")) + ".wav" print(filename)
p = pyaudio.PyAudio() stream = p.open(format=FORMAT, channels=CHANNELS, rate=RATE, input=True, frames_per_buffer=FRAMES_PER_BUFFER)
isLoop = True buffer = []
try: while (isLoop): raw_data = stream.read(FRAMES_PER_BUFFER) if len(raw_data) > 0: buffer.append(raw_data)
except KeyboardInterrupt: isLoop = False print("停止录音") except Exception as e: print(f"录音出错：{e}") finally: stream.stop_stream() stream.close() p.terminate()
wf = wave.open(filename, 'wb') wf.setnchannels(CHANNELS) wf.setsampwidth(p.get_sample_size(FORMAT)) wf.setframerate(RATE) wf.writeframes(b''.join(buffer)) wf.close()

#! /usr/scripts/env python3 # -*- coding: UTF-8 -*- ############################################## # Home : http://netkiller.github.io # Author: Neo <netkiller@msn.com> # Data: 2026-02-03 # Description: mp3 文件录音 ############################################## import datetime import io
import pyaudio from pydub import AudioSegment
FORMAT = pyaudio.paInt16 CHANNELS = 1 RATE = 16000 FRAMES_PER_BUFFER = 2048
if __name__ == '__main__': filename = f"test-" + str(datetime.datetime.now().strftime("%H%M%S")) + ".mp3" print(f"录音：{filename}")
p = pyaudio.PyAudio() stream = p.open(format=FORMAT, channels=CHANNELS, rate=RATE, input=True, frames_per_buffer=FRAMES_PER_BUFFER)
isLoop = True pcm_buffer = []
try: while (isLoop): raw_data = stream.read(FRAMES_PER_BUFFER) if len(raw_data) > 0: pcm_buffer.append(raw_data)
except KeyboardInterrupt: isLoop = False print("停止录音") except Exception as e: print(f"录音出错：{e}") finally: stream.stop_stream() stream.close() p.terminate()
# 内存里加载PCM数据流到 AudioSegment audio = AudioSegment.from_raw(io.BytesIO(b''.join(pcm_buffer)), sample_width=2, channels=CHANNELS, frame_rate=RATE )
mp3_buffer = io.BytesIO() mp3_buffer.seek(0) audio.export(mp3_buffer, 'mp3')
mp3_data = mp3_buffer.getbuffer().tobytes()
file = open(filename, 'wb') file.write(mp3_data) file.close()

